(3, '2018年6月第2套', '师生之间的信任', 'For this part, you are allowed 30 minutes to write an essay on the importance of building trust between teachers and students. You can cite examples to illustrate your views. You should write at least 150 words but no more than 200 words.', 2018, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2018年6月第2套', 1),
(3, '2018年6月第3套', '企业与消费者之间的信任', 'For this part, you are allowed 30 minutes to write an essay on the importance of building trust between businesses and consumers. You can cite examples to illustrate your views. You should write at least 150 words but no more than 200 words.', 2018, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2018年6月第3套', 1);
