INSERT INTO essay_prompt (stage_id, paper, title, prompt_text, exam_year, image_url, image_description, material_text, task, word_count_min, word_count_max, max_score, source, is_active) VALUES
(3, '2017年6月第1套', '理科还是文科', 'Suppose you are asked to give advice on whether to major in science or humanities at college, write an essay to state your opinion. You are required to write at least 150 words but no more than 200 words.', 2017, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2017年6月第1套', 1),
(3, '2017年6月第2套', '职业院校还是大学', 'For this part, you are allowed 30 minutes to write an essay on whether to attend a vocational college or a university. You should write at least 150 words but no more than 200 words.', 2017, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2017年6月第2套', 1),
(3, '2017年6月第3套', '国内还是国外上大学', 'Suppose you are asked to give advice on whether to attend college at home or abroad, write an essay to state your opinion. You are required to write at least 150 words but no more than 200 words.', 2017, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2017年6月第3套', 1);
INSERT INTO essay_prompt (stage_id, paper, title, prompt_text, exam_year, image_url, image_description, material_text, task, word_count_min, word_count_max, max_score, source, is_active) VALUES
(3, '2016年12月第1套', '发明的重要性', 'For this part, you are allowed 30 minutes to write a short essay on invention. Your essay should include the importance of invention and measures to be taken to encourage invention. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年12月第1套', 1),
(3, '2016年12月第2套', '创新的重要性', 'For this part, you are allowed 30 minutes to write a short essay on innovation. Your essay should include the importance of innovation and measures to be taken to encourage innovation. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年12月第2套', 1),
(3, '2016年12月第3套', '创造的重要性', 'For this part, you are allowed 30 minutes to write a short essay on creation. Your essay should include the importance of creation and measures to be taken to encourage creation. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年12月第3套', 1);
INSERT INTO essay_prompt (stage_id, paper, title, prompt_text, exam_year, image_url, image_description, material_text, task, word_count_min, word_count_max, max_score, source, is_active) VALUES
(3, '2016年6月第1套', '虚拟世界生活', 'For this part, you are allowed 30 minutes to write a short essay on living in the virtual world. Try to imagine what will happen when people spend more and more time in the virtual world instead of interacting in the real world. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年6月第1套', 1),
(3, '2016年6月第2套', '机器人的使用', 'For this part, you are allowed 30 minutes to write a short essay on the use of robots. Try to imagine what will happen when more and more robots take the place of human beings in industry as well as people''s daily lives. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年6月第2套', 1),
(3, '2016年6月第3套', '在线学习', 'For this part, you are allowed 30 minutes to write a short essay on e-learning. Try to imagine what will happen when more and more people study online instead of attending school. You are required to write at least 150 words but no more than 200 words.', 2016, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2016年6月第3套', 1);
INSERT INTO essay_prompt (stage_id, paper, title, prompt_text, exam_year, image_url, image_description, material_text, task, word_count_min, word_count_max, max_score, source, is_active) VALUES
(3, '2015年12月第1套', '网络虚假信息的危害', 'For this part, you are allowed 30 minutes to write a short essay based on the picture below. You should focus on the harm caused by misleading information online. You are required to write at least 150 words but no more than 200 words.', 2015, NULL, '漫画：一个人坐在电脑前浏览网页，旁边站着一个人端着咖啡杯。画面表现的是人们在网上接触到大量虚假和误导性信息的场景。', NULL, 'task1', 150, 200, 106, 'CET-6 2015年12月第1套', 1),
(3, '2015年12月第2套', '社交网站对阅读的影响', 'For this part, you are allowed 30 minutes to write a short essay based on the picture below. You should focus on the impact of social networking websites on reading. You are required to write at least 150 words but no more than 200 words.', 2015, NULL, '漫画：一个人坐在桌前使用电脑，配文："I love reading. I read about 3 hours a day. My favorite book is Facebook." 注释说明Facebook是一个社交网站的名称。画面讽刺地表达了人们将浏览社交网站等同于阅读的现象。', NULL, 'task1', 150, 200, 106, 'CET-6 2015年12月第2套', 1),
(3, '2015年12月第3套', '信息技术时代获取有用信息的困难', 'For this part, you are allowed 30 minutes to write a short essay based on the picture below. You should focus on the difficulty in acquiring useful information in spite of advanced information technology. You are required to write at least 150 words but no more than 200 words.', 2015, NULL, '漫画：几个人围坐在会议桌旁，桌上有电脑等设备，配文："We have lots of information technology. We just don''t have much useful information." 画面表达了尽管信息技术高度发达，人们仍然难以获取真正有用信息的悖论。', NULL, 'task1', 150, 200, 106, 'CET-6 2015年12月第3套', 1);
INSERT INTO essay_prompt (stage_id, paper, title, prompt_text, exam_year, image_url, image_description, material_text, task, word_count_min, word_count_max, max_score, source, is_active) VALUES
(3, '2015年6月第1套', '知识与实践', 'For this part, you are allowed 30 minutes to write an essay commenting on the saying "Knowledge is a treasure, but practice is the key to it." You can cite one example or two to illustrate your point of view. You should write at least 150 words but no more than 200 words.', 2015, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2015年6月第1套', 1),
(3, '2015年6月第2套', '好奇心的力量', 'For this part, you are allowed 30 minutes to write an essay commenting on Albert Einstein''s remark "I have no special talents. I am only passionately curious." You can give an example or two to illustrate your point of view. You should write at least 150 words but no more than 200 words.', 2015, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2015年6月第2套', 1),
(3, '2015年6月第3套', '把小事做好', 'For this part, you are allowed 30 minutes to write an essay commenting on the saying "If you cannot do great things, do small things in a great way." You can cite examples to illustrate your point of view. You should write at least 150 words but no more than 200 words.', 2015, NULL, NULL, NULL, 'task1', 150, 200, 106, 'CET-6 2015年6月第3套', 1);
